class NotaInvalida(ValueError):
    pass

def validar_nota(nota):
    if nota < 0 or nota > 10:
        raise NotaInvalida(f'Nota {nota} fora do intervalo 0-10')
    return nota

print(validar_nota(7.5))
print(validar_nota(0.0))
print(validar_nota(10.0))
try:
    validar_nota(-1)
except NotaInvalida:
    print('NotaInvalida')
try:
    validar_nota(11)
except NotaInvalida:
    print('NotaInvalida')
